/** Returns true if `v` is a NodeData — has `type` string and `fields` object or `text` string. */
export function isNodeData<K extends SyntaxKindType>(v: NodeData<K> | TreeNode<K> | NodeFields<K> | {kind?: K}): v is NodeData<K> {
  if (v === null || typeof v !== 'object') return false;
  const o = v as Record<string, unknown>;
  if (typeof o['type'] !== 'string') return false;
  return (o['fields'] !== null && typeof o['fields'] === 'object') || typeof o['text'] === 'string';
}

/** Returns true if `v` is a TreeNode (SgNode-compatible) — has `type`, `field()`, and `text()`. */
export function isTreeNode<K extends SyntaxKindType>(v: NodeData<K> | TreeNode<K> | NodeFields<K> | {kind?: K}): v is TreeNode<K> {
  if (v === null || typeof v !== 'object') return false;
  const o = v as Record<string, unknown>;
  return typeof o['type'] === 'string' && typeof o['field'] === 'function' && typeof o['text'] === 'function';
}

/** Returns true if `v` is a plain FromInput object — not a NodeData and not a TreeNode. */
export function isFromInput<K extends SyntaxKindType>(v: NodeData<K> | TreeNode<K> | NodeFields<K> | {kind?: K}): v is NodeFields<K> {
  if (v === null || typeof v !== 'object') return false;
  if (isNodeData(v)) return false;
  if (isTreeNode(v)) return false;
  return true;
}

